+    #[test]
+    fn egraph_debug_default() {
+        let eg = EGraph::new();
+        let dbg = format!("{eg:?}");
+        assert!(dbg.contains("EGraph"));
+    }
+
+    #[test]
+    fn egraph_class_nodes_cloned() {
+        let mut eg = EGraph::new();
+        let a = eg.add_leaf("single");
+        let nodes = eg.class_nodes_cloned(a).expect("class exists");
